package ru.memearena.ratelimit; import org.springframework.stereotype.Component; import java.time.*; import java.util.concurrent.*;
@Component public class InMemoryRateLimiterService implements RateLimiterService { private record Bucket(long windowStart,int count){} private final ConcurrentMap<String,Bucket> buckets=new ConcurrentHashMap<>(); public void check(String name,String key,int limit,long windowSeconds){long now=Instant.now().getEpochSecond(); String k=name+":"+key; Bucket b=buckets.compute(k,(kk,old)->{ if(old==null||now-old.windowStart>=windowSeconds) return new Bucket(now,1); return new Bucket(old.windowStart,old.count+1);}); if(b.count>limit) throw new RateLimitExceededException(windowSeconds-(now-b.windowStart)); } }
